-- =============================================================================
-- MODULE: Strings & Runes
-- =============================================================================

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('reverse-words','Strings & Runes','function','go','Reverse Words','Given a string, reverse the order of words. A word is a sequence of non-space characters. Reduce multiple spaces to a single space and trim leading/trailing spaces.','ReverseWords','string',ARRAY['string']::text[],ARRAY['Split the string on spaces and collect non-empty tokens.','Reverse the token slice then rejoin with single spaces.','Use strings.Fields to handle whitespace automatically.'],2,90,ARRAY['strings','words','medium'],true,'MANUAL:reverse-words',$$Reverse the order of words in a string.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('["the sky is blue"]'::jsonb,'"blue is sky the"',false,1),('["  hello   world  "]'::jsonb,'"world hello"',false,2),('["a good   example"]'::jsonb,'"example good a"',false,3),('[""]'::jsonb,'""',true,4)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('is-anagram','Strings & Runes','function','go','Valid Anagram','Given two strings s and t, return true if t is an anagram of s, false otherwise.','IsAnagram','bool',ARRAY['string','string']::text[],ARRAY['An anagram has the same character counts.','Use a frequency map or an array of 26 zeroes for lowercase letters.','Strings may contain Unicode; normalise to lowercase.'],1,60,ARRAY['strings','hashmap','basic'],true,'MANUAL:is-anagram',$$Check if two strings are anagrams.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('["anagram","nagaram"]'::jsonb,'true',false,1),('["rat","car"]'::jsonb,'false',false,2),('["",""]'::jsonb,'true',false,3),('["a","aa"]'::jsonb,'false',true,4)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('is-palindrome','Strings & Runes','function','go','Is Palindrome','Return true if the given string reads the same forwards and backwards, false otherwise. Compare only alphanumeric characters and ignore case.','IsPalindrome','bool',ARRAY['string']::text[],ARRAY['Use two pointers moving from both ends toward the centre.','Skip non-alphanumeric characters using unicode.IsLetter/IsDigit.','Convert characters to lowercase before comparing.'],1,60,ARRAY['strings','two-pointers','basic'],true,'MANUAL:is-palindrome',$$Check whether a string is a palindrome.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('["A man, a plan, a canal: Panama"]'::jsonb,'true',false,1),('["race a car"]'::jsonb,'false',false,2),('[" "]'::jsonb,'true',false,3),('["0P"]'::jsonb,'false',true,4)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('first-unique-char','Strings & Runes','function','go','First Unique Character','Given a string, find the index of the first non-repeating character and return it. If no unique character exists, return -1.','FirstUniqueChar','int',ARRAY['string']::text[],ARRAY['Count frequencies of each character first.','Iterate the string a second time; return the first index with count 1.','Use a map[rune]int for full Unicode support.'],2,90,ARRAY['strings','hashmap','medium'],true,'MANUAL:first-unique-char',$$Find the first non-repeating character index.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
