WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('rune-frequency','Strings & Runes','function','go','Rune Frequency','Return a map counting each rune (character) in the input string.','RuneFrequency','map[string]int',ARRAY['string']::text[],ARRAY['Iterate over the string using range to get runes.','Increment a map[string]int entry for each rune.','Empty string returns an empty map.'],1,60,ARRAY['strings','runes','maps','basic'],true,'MANUAL:rune-frequency',$$Count rune frequency in a string.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('["hello"]'::jsonb,'{"h":1,"e":1,"l":2,"o":1}',false,1),('["golang"]'::jsonb,'{"g":1,"o":1,"l":1,"a":1,"n":1}',false,2),('[""]'::jsonb,'{}',true,3)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('compress-string','Strings & Runes','function','go','String Compression','Compress a string by replacing runs of identical characters with the character followed by the count. If the compressed string is not shorter, return the original.','CompressString','string',ARRAY['string']::text[],ARRAY['Iterate through the string counting consecutive identical characters.','Append the character only if count > 1 after the first occurrence.','Compare lengths at the end to decide which to return.'],2,100,ARRAY['strings','compression','medium'],true,'MANUAL:compress-string',$$Compress repeated characters with count.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('["aabcccccaaa"]'::jsonb,'"a2b1c5a3"',false,1),('["abcdef"]'::jsonb,'"abcdef"',false,2),('["aabb"]'::jsonb,'"aabb"',false,3),('[""]'::jsonb,'""',true,4)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('strstr','Strings & Runes','function','go','Find Substring','Return the index of the first occurrence of needle in haystack, or -1 if needle is not part of haystack.','StrStr','int',ARRAY['string','string']::text[],ARRAY['Slide a window of length len(needle) over haystack.','Optimise by stopping early when insufficient characters remain.','An empty needle returns 0.'],2,90,ARRAY['strings','searching','medium'],true,'MANUAL:strstr',$$Find the first occurrence of a substring.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('["sadbutsad","sad"]'::jsonb,'0',false,1),('["leetcode","leeto"]'::jsonb,'-1',false,2),('["hello",""]'::jsonb,'0',false,3),('["abc","c"]'::jsonb,'2',true,4)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('roman-to-int','Strings & Runes','function','go','Roman to Integer','Convert a Roman numeral string to an integer. Input is guaranteed to be valid and in range 1-3999.','RomanToInt','int',ARRAY['string']::text[],ARRAY['Map characters to values: I=1, V=5, X=10, L=50, C=100, D=500, M=1000.','If a smaller value appears before a larger one, subtract it.','Otherwise add the value.'],2,110,ARRAY['strings','numbers','medium'],true,'MANUAL:roman-to-int',$$Convert Roman numeral to integer.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('["III"]'::jsonb,'3',false,1),('["LVIII"]'::jsonb,'58',false,2),('["MCMXCIV"]'::jsonb,'1994',false,3),('["IV"]'::jsonb,'4',true,4)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('caesar-cipher','Strings & Runes','function','go','Caesar Cipher','Encrypt a string by shifting each letter by k positions in the alphabet (A-Z, a-z). Preserve case. Non-letter characters pass through unchanged.','CaesarCipher','string',ARRAY['string','int']::text[],ARRAY['Normalise k to the range 0-25 using modulo.','Check if a rune is uppercase or lowercase to determine the base.','Use (rune - base + k) % 26 + base formula.'],2,90,ARRAY['strings','cipher','medium'],true,'MANUAL:caesar-cipher',$$Shift letters by k positions in the alphabet.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
