WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('length-of-last-word','Strings & Runes','function','go','Length of Last Word','Given a string consisting of words and spaces, return the length of the last word. A word is a maximal substring of non-space characters.','LengthOfLastWord','int',ARRAY['string']::text[],ARRAY['Trim trailing spaces first.','Start from the end and count until hitting a space.','Edge case: a single word with no spaces.'],1,50,ARRAY['strings','basic'],true,'MANUAL:length-of-last-word',$$Return the length of the last word in a string.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
