WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('factorial','Math & Recursion','function','go','Factorial','Return n! (n factorial) for a non-negative integer n. 0! = 1.','Factorial','int',ARRAY['int']::text[],ARRAY['Base case: 0! = 1 and 1! = 1.','Use recursion: n! = n * (n-1)! for n > 1.','Be careful with large n; assume n <= 12 for int overflow safety.'],1,50,ARRAY['math','recursion','basic'],true,'MANUAL:factorial',$$Compute n factorial recursively.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[5]'::jsonb,'120',false,1),('[0]'::jsonb,'1',false,2),('[1]'::jsonb,'1',false,3),('[10]'::jsonb,'3628800',true,4)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('fibonacci','Math & Recursion','function','go','Fibonacci','Return the n-th number in the Fibonacci sequence (0-indexed). F(0) = 0, F(1) = 1, F(n) = F(n-1) + F(n-2).','Fibonacci','int',ARRAY['int']::text[],ARRAY['Base cases: F(0)=0, F(1)=1.','Use memoisation for efficiency if using recursion.','Iterative approach is O(n) time, O(1) space.'],1,50,ARRAY['math','recursion','basic'],true,'MANUAL:fibonacci',$$Compute the n-th Fibonacci number.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[2]'::jsonb,'1',false,1),('[3]'::jsonb,'2',false,2),('[10]'::jsonb,'55',false,3),('[0]'::jsonb,'0',true,4)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('gcd','Math & Recursion','function','go','Greatest Common Divisor','Return the greatest common divisor of two non-negative integers using Euclid algorithm.','GCD','int',ARRAY['int','int']::text[],ARRAY['If b=0, return a. Otherwise recurse with GCD(b, a%b).','Works for positive integers; if both are 0 return 0.','Euclid algorithm converges in O(log min(a,b)) steps.'],1,60,ARRAY['math','recursion','basic'],true,'MANUAL:gcd',$$Compute the greatest common divisor using Euclid algorithm.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[12,8]'::jsonb,'4',false,1),('[17,5]'::jsonb,'1',false,2),('[100,25]'::jsonb,'25',false,3),('[0,5]'::jsonb,'5',true,4),('[0,0]'::jsonb,'0',true,5)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('lcm','Math & Recursion','function','go','Least Common Multiple','Return the least common multiple of two non-negative integers.','LCM','int',ARRAY['int','int']::text[],ARRAY['LCM(a,b) = a * b / GCD(a,b).','Be careful of overflow -- cast to int64 or use division before multiplication.','If either a or b is 0, LCM is 0.'],1,60,ARRAY['math','numbers','basic'],true,'MANUAL:lcm',$$Compute the least common multiple of two numbers.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
