WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('digit-sum','Math & Recursion','function','go','Sum of Digits','Return the sum of the digits of a non-negative integer.','DigitSum','int',ARRAY['int']::text[],ARRAY['Repeatedly extract the last digit with n % 10 and add to sum.','Divide n by 10 to remove the last digit.','For n=0 return 0.'],1,40,ARRAY['math','numbers','basic'],true,'MANUAL:digit-sum',$$Sum the digits of a non-negative integer.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[123]'::jsonb,'6',false,1),('[9999]'::jsonb,'36',false,2),('[0]'::jsonb,'0',false,3),('[1001]'::jsonb,'2',true,4)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('power-of','Math & Recursion','function','go','Power Of','Compute base raised to the power of exp (non-negative integer exponent). Return 0^0 = 1.','PowerOf','int',ARRAY['int','int']::text[],ARRAY['Base case: x^0 = 1.','Use exponentiation by squaring for efficiency.','Handle negative base correctly (sign alternates with exponent parity).'],2,80,ARRAY['math','recursion','medium'],true,'MANUAL:power-of',$$Compute base^exp for integer exponent.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[2,3]'::jsonb,'8',false,1),('[5,0]'::jsonb,'1',false,2),('[0,0]'::jsonb,'1',false,3),('[-2,3]'::jsonb,'-8',true,4),('[2,10]'::jsonb,'1024',true,5)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('collatz-steps','Math & Recursion','function','go','Collatz Steps','Given a positive integer n, return the number of steps to reach 1: if n is even divide by 2, else multiply by 3 and add 1.','CollatzSteps','int',ARRAY['int']::text[],ARRAY['Base case: when n=1, return 0.','Recursively compute: if even -> n/2, if odd -> 3n+1.','Assume the conjecture holds for all inputs up to 10^6.'],2,80,ARRAY['math','recursion','medium'],true,'MANUAL:collatz-steps',$$Count steps to reach 1 following the Collatz sequence.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[1]'::jsonb,'0',false,1),('[12]'::jsonb,'9',false,2),('[6]'::jsonb,'8',false,3),('[2]'::jsonb,'1',true,4)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('perfect-number','Math & Recursion','function','go','Perfect Number','A perfect number equals the sum of its proper positive divisors. Return true if n is perfect, false otherwise.','IsPerfect','bool',ARRAY['int']::text[],ARRAY['A proper divisor excludes the number itself.','Check divisors from 1 to sqrt(n) for efficiency.','6, 28, 496 are the first three perfect numbers.'],2,80,ARRAY['math','numbers','medium'],true,'MANUAL:perfect-number',$$Check whether a number is perfect.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[6]'::jsonb,'true',false,1),('[28]'::jsonb,'true',false,2),('[12]'::jsonb,'false',false,3),('[1]'::jsonb,'false',true,4)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('sieve-of-eratosthenes','Math & Recursion','function','go','Sieve of Eratosthenes','Return all prime numbers less than or equal to n. Return empty slice if n < 2.','SieveOfEratosthenes','[]int',ARRAY['int']::text[],ARRAY['Create a boolean array of size n+1 initialised to true.','Mark multiples of each prime starting from 2.','Collect indices still marked true after sieving.'],2,100,ARRAY['math','primes','medium'],true,'MANUAL:sieve-of-eratosthenes',$$Generate primes up to n using the Sieve.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
